    if (!isMounted || !auth.currentUser) return;

    try {
      await auth.currentUser.reload();
      if (isMounted && auth.currentUser.emailVerified) {
        // Use auth state change instead of page reload
        // The App component will handle navigation automatically
        clearInterval(interval);
      }
    } catch (error) {
      console.error('Error checking email verification:', error);
    }
  }, 3000);

  return () => {
    isMounted = false;
    clearInterval(interval);
  };
}, []);

