export const ALLOWED_IMAGE_TYPES = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp'];
export const MAX_IMAGE_SIZE_BYTES = 5 * 1024 * 1024; // 5MB
export const MAX_IMAGE_DIMENSION = 4096;

export interface ImageValidationResult {
  valid: boolean;
  error?: string;
}

export async function validateImage(file: File): Promise<ImageValidationResult> {
  // Check file type
  if (!ALLOWED_IMAGE_TYPES.includes(file.type)) {
    return { valid: false, error: 'סוג קובץ לא נתמך. אנא העלה תמונת JPG, PNG או WebP.' };
  }

  // Check file size
  if (file.size > MAX_IMAGE_SIZE_BYTES) {
    return { valid: false, error: 'התמונה גדולה מדי. גודל מקסימלי: 5MB.' };
  }

  // Check image dimensions
  return new Promise((resolve) => {
    const img = new Image();
    const url = URL.createObjectURL(file);

    img.onload = () => {
      URL.revokeObjectURL(url);
      if (img.width > MAX_IMAGE_DIMENSION || img.height > MAX_IMAGE_DIMENSION) {
        resolve({ valid: false, error: 'רזולוציית התמונה גבוהה מדי. מקסימום: 4096x4096 פיקסלים.' });
      } else {
        resolve({ valid: true });
      }
    };

    img.onerror = () => {
      URL.revokeObjectURL(url);
      resolve({ valid: false, error: 'קובץ התמונה פגום.' });
    };

    img.src = url;
  });
}

