if (userLocation && job.coordinates) {
  const R = 6371; // Earth radius in km
  const dLat = (job.coordinates.lat - userLocation.lat) * Math.PI / 180;
  const dLon = (job.coordinates.lng - userLocation.lng) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(userLocation.lat * Math.PI / 180) * Math.cos(job.coordinates.lat * Math.PI / 180) *
    Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  const distance = R * c;
  setDistanceInfo({ text: `כ-${distance.toFixed(1)} ק"מ (קו אווירי)` });
}
